import{_ as t}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{c as e,o as r,ad as l}from"./chunks/mermaid.Cb40Nz1P.js";import"./chunks/cytoscape.C2CwDKBM.js";import"./chunks/dayjs.C32PoDnw.js";const q=JSON.parse('{"title":"Claude.ai 平台功能指南","description":"","frontmatter":{},"headers":[],"relativePath":"zh/products/ai-coding/claude/claude-ai.md","filePath":"zh/products/ai-coding/claude/claude-ai.md"}'),i={name:"zh/products/ai-coding/claude/claude-ai.md"};function n(o,a,s,d,h,c){return r(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="claude-ai-平台功能指南" tabindex="-1">Claude.ai 平台功能指南 <a class="header-anchor" href="#claude-ai-平台功能指南" aria-label="Permalink to &quot;Claude.ai 平台功能指南&quot;">​</a></h1><blockquote><p>claude.ai 是 Anthropic 的核心产品界面，支持网页、手机 App、桌面 App 三端同步。作为 Pro 会员，你能使用远超免费版的功能集。本文系统梳理所有 Pro 专属或增强功能。</p></blockquote><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><table tabindex="0"><thead><tr><th>平台</th><th>地址/方式</th></tr></thead><tbody><tr><td>网页版</td><td><a href="https://claude.ai" target="_blank" rel="noreferrer">claude.ai</a></td></tr><tr><td>iOS App</td><td>App Store 搜索 &quot;Claude&quot;</td></tr><tr><td>Android App</td><td>Google Play 搜索 &quot;Claude&quot;</td></tr><tr><td>桌面 App (macOS/Win)</td><td><a href="https://claude.ai/download" target="_blank" rel="noreferrer">下载地址</a></td></tr></tbody></table><p>所有平台共享同一账号、对话历史和项目数据。</p><hr><h2 id="projects-专属工作区" tabindex="-1">Projects 专属工作区 <a class="header-anchor" href="#projects-专属工作区" aria-label="Permalink to &quot;Projects 专属工作区&quot;">​</a></h2><h3 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h3><p>Projects 是 Claude.ai 中的独立工作区，每个 Project 有自己的：</p><ul><li><strong>聊天历史</strong>：与该项目相关的所有对话</li><li><strong>知识库</strong>：上传的文档、代码、参考资料</li><li><strong>自定义指令</strong>：定义 Claude 在这个项目中的角色和行为规范</li></ul><h3 id="核心优势" tabindex="-1">核心优势 <a class="header-anchor" href="#核心优势" aria-label="Permalink to &quot;核心优势&quot;">​</a></h3><p><strong>持久上下文</strong>：普通对话每次都从零开始，Project 让 Claude 在每次对话时都能读取你上传的背景资料，无需重复粘贴。</p><p><strong>RAG 知识库（Pro 专属）</strong>：上传大量文档后，Pro 用户享有 10 倍容量扩展，Claude 会自动检索相关片段来回答问题，而不是死记硬背全部内容。</p><p><strong>自定义角色</strong>：在 Project 指令中写明 Claude 的角色，例如：&quot;你是一位熟悉我们公司技术栈的高级前端工程师，代码风格遵循我上传的规范文档。&quot;</p><h3 id="如何使用" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用" aria-label="Permalink to &quot;如何使用&quot;">​</a></h3><ol><li>在左侧边栏点击 <strong>+ 新建项目</strong></li><li>给项目命名（如&quot;前端重构项目&quot;）</li><li>点击 <strong>添加到项目知识库</strong> 上传相关文档</li><li>在 <strong>项目指令</strong> 中写下 Claude 的角色定义和行为规范</li><li>在项目内开始对话，Claude 始终带着这些上下文</li></ol><h3 id="支持的知识库文件类型" tabindex="-1">支持的知识库文件类型 <a class="header-anchor" href="#支持的知识库文件类型" aria-label="Permalink to &quot;支持的知识库文件类型&quot;">​</a></h3><p>PDF、Word、Excel、TXT、Markdown、代码文件、CSV 等常见格式。单文件最大 10MB，项目总容量视计划而定（Pro 用户有大幅扩展）。</p><h3 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h3><ul><li><strong>一个项目对应一个工作域</strong>：如&quot;产品设计&quot;、&quot;技术文档&quot;、&quot;市场研究&quot;分别建立独立项目</li><li><strong>上传规范文档</strong>：代码规范、品牌手册、API 文档放入知识库，Claude 会自动参考</li><li><strong>写好指令</strong>：指令越具体，Claude 越能给出符合你期望的回答</li></ul><hr><h2 id="extended-thinking-深度推理" tabindex="-1">Extended Thinking 深度推理 <a class="header-anchor" href="#extended-thinking-深度推理" aria-label="Permalink to &quot;Extended Thinking 深度推理&quot;">​</a></h2><h3 id="是什么-1" tabindex="-1">是什么 <a class="header-anchor" href="#是什么-1" aria-label="Permalink to &quot;是什么&quot;">​</a></h3><p>Extended Thinking（扩展思考）是 Claude 4 和 Claude 3.7 Sonnet 的专属能力。启用后，Claude 在回答前会花更多时间<strong>分解问题、制定方案、探索不同路径</strong>，类似人类的&quot;慢思考&quot;。</p><p>你会看到一个 <strong>&quot;Thinking...&quot;</strong> 指示器和计时器，完成后可以展开查看 Claude 的推理过程摘要。</p><h3 id="适合什么场景" tabindex="-1">适合什么场景 <a class="header-anchor" href="#适合什么场景" aria-label="Permalink to &quot;适合什么场景&quot;">​</a></h3><p>✅ <strong>适合</strong>：</p><ul><li>复杂数学推导和物理问题</li><li>竞赛级编程题</li><li>多步骤项目规划</li><li>深度文档分析和对比</li><li>需要权衡多方案的技术决策</li></ul><p>❌ <strong>不适合</strong>（会浪费时间）：</p><ul><li>简单问答（今天天气如何）</li><li>基础写作（帮我写个欢迎邮件）</li><li>常规代码补全</li></ul><h3 id="如何启用" tabindex="-1">如何启用 <a class="header-anchor" href="#如何启用" aria-label="Permalink to &quot;如何启用&quot;">​</a></h3><ol><li>在模型选择器中选择 <strong>Claude 4</strong>（或 Claude 3.7 Sonnet）</li><li>点击对话框左下角的 <strong>搜索与工具</strong></li><li>打开 <strong>Extended Thinking</strong> 开关</li></ol><p><strong>注意</strong>：启用 Extended Thinking 会开启一个新对话，无法在已有对话中途切换。</p><h3 id="使用技巧" tabindex="-1">使用技巧 <a class="header-anchor" href="#使用技巧" aria-label="Permalink to &quot;使用技巧&quot;">​</a></h3><ul><li>问题要具体清晰，模糊问题会让推理方向跑偏</li><li>展开&quot;Thinking&quot;区域了解 Claude 的推理逻辑，有助于你评估答案可靠性</li><li>对于耗时任务，这个模式会明显消耗更多使用额度</li></ul><hr><h2 id="research-深度研究" tabindex="-1">Research 深度研究 <a class="header-anchor" href="#research-深度研究" aria-label="Permalink to &quot;Research 深度研究&quot;">​</a></h2><h3 id="是什么-2" tabindex="-1">是什么 <a class="header-anchor" href="#是什么-2" aria-label="Permalink to &quot;是什么&quot;">​</a></h3><p>Research 是 Claude 的<strong>代理式联网研究</strong>功能。与普通网络搜索不同，它能进行多轮相互关联的搜索，自主决定下一步要调查什么，最终给出带有可验证引用的完整答案。</p><p>类比：普通搜索是&quot;帮你搜一次&quot;，Research 是&quot;帮你研究一个课题&quot;。</p><h3 id="适合什么场景-1" tabindex="-1">适合什么场景 <a class="header-anchor" href="#适合什么场景-1" aria-label="Permalink to &quot;适合什么场景&quot;">​</a></h3><ul><li>调研某个技术方案的优劣和行业现状</li><li>了解竞品功能和市场格局</li><li>收集某个话题的多方观点</li><li>查找最新的行业数据和报告</li><li>任何需要综合多个信息源的问题</li></ul><h3 id="如何使用-1" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用-1" aria-label="Permalink to &quot;如何使用&quot;">​</a></h3><ol><li>在聊天界面左下角找到 <strong>Research</strong> 按钮（白色=未启用，蓝色=已启用）</li><li>点击启用（<strong>必须同时开启网络搜索</strong>）</li><li>提问，Claude 会自动展开多轮研究</li></ol><p>若 Claude 没有主动使用 Research，可以明确要求：&quot;请使用 Research 工具深入调查这个问题。&quot;</p><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><ul><li>Research 功能会话消耗比普通对话更快（因为需要检索多个来源）</li><li>结果会附带来源引用，方便你验证</li><li>适用于 Pro、Max、Team、Enterprise 计划，支持网页版、Desktop 和手机 App</li></ul><hr><h2 id="网络搜索" tabindex="-1">网络搜索 <a class="header-anchor" href="#网络搜索" aria-label="Permalink to &quot;网络搜索&quot;">​</a></h2><h3 id="是什么-3" tabindex="-1">是什么 <a class="header-anchor" href="#是什么-3" aria-label="Permalink to &quot;是什么&quot;">​</a></h3><p>网络搜索让 Claude 能够获取<strong>实时互联网信息</strong>，突破训练数据截止日期的限制。</p><h3 id="如何启用-1" tabindex="-1">如何启用 <a class="header-anchor" href="#如何启用-1" aria-label="Permalink to &quot;如何启用&quot;">​</a></h3><p>在对话框左下角点击 <strong>搜索与工具 → 网络搜索</strong> 开启。</p><h3 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><ul><li>最新新闻和事件</li><li>实时数据（股价、天气、汇率）</li><li>近期发布的技术文档</li><li>任何可能在训练截止日期之后发生变化的信息</li></ul><h3 id="与-research-的区别" tabindex="-1">与 Research 的区别 <a class="header-anchor" href="#与-research-的区别" aria-label="Permalink to &quot;与 Research 的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th style="text-align:center;">网络搜索</th><th style="text-align:center;">Research</th></tr></thead><tbody><tr><td>搜索轮次</td><td style="text-align:center;">1-2 次</td><td style="text-align:center;">多轮自主探索</td></tr><tr><td>适合场景</td><td style="text-align:center;">快速查询事实</td><td style="text-align:center;">深度调研课题</td></tr><tr><td>时间消耗</td><td style="text-align:center;">几秒</td><td style="text-align:center;">几分钟</td></tr><tr><td>额度消耗</td><td style="text-align:center;">较少</td><td style="text-align:center;">较多</td></tr></tbody></table><hr><h2 id="交互式图表与可视化" tabindex="-1">交互式图表与可视化 <a class="header-anchor" href="#交互式图表与可视化" aria-label="Permalink to &quot;交互式图表与可视化&quot;">​</a></h2><blockquote><p>2026 年 3 月新功能：Claude 现在可以生成真正可交互的图表、图形和数据可视化，而不仅仅是静态图片。</p></blockquote><h3 id="是什么-4" tabindex="-1">是什么 <a class="header-anchor" href="#是什么-4" aria-label="Permalink to &quot;是什么&quot;">​</a></h3><p>Claude 可以直接在对话中生成<strong>可交互的可视化内容</strong>，用户可以在界面内直接操作：缩放、筛选、悬停查看详情、动态更新数据等。</p><h3 id="支持类型" tabindex="-1">支持类型 <a class="header-anchor" href="#支持类型" aria-label="Permalink to &quot;支持类型&quot;">​</a></h3><ul><li><strong>交互式折线/柱/饼图</strong>：数据点可悬停查看，支持缩放和平移</li><li><strong>流程图 / 思维导图</strong>：节点可拖拽，支持折叠展开</li><li><strong>数据仪表盘</strong>：多图联动，实时过滤</li><li><strong>网络关系图</strong>：节点连接可视化，支持力导向布局</li></ul><h3 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h3><p>直接描述需求，Claude 会判断是否生成交互式内容：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我把这份销售数据做成可以按月份筛选的交互式柱状图</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>画一个可以折叠的组件树结构图，展示 React 应用的组件层级</span></span></code></pre></div><p>生成后在 Artifact 窗口直接交互，也可以导出为独立 HTML 文件。</p><hr><h2 id="artifacts-独立内容输出" tabindex="-1">Artifacts 独立内容输出 <a class="header-anchor" href="#artifacts-独立内容输出" aria-label="Permalink to &quot;Artifacts 独立内容输出&quot;">​</a></h2><h3 id="是什么-5" tabindex="-1">是什么 <a class="header-anchor" href="#是什么-5" aria-label="Permalink to &quot;是什么&quot;">​</a></h3><p>Artifacts 是 Claude 在对话旁边<strong>独立窗口中生成的内容</strong>，与聊天分离展示，方便编辑、预览和导出。当内容通常超过 15 行，且能独立存在时会自动触发。</p><h3 id="支持的-artifact-类型" tabindex="-1">支持的 Artifact 类型 <a class="header-anchor" href="#支持的-artifact-类型" aria-label="Permalink to &quot;支持的 Artifact 类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td>文档</td><td>Markdown 或纯文本</td><td>报告、文章、README</td></tr><tr><td>代码</td><td>带语法高亮的代码片段</td><td>React 组件、Python 脚本</td></tr><tr><td>网站</td><td>可预览的 HTML+CSS+JS</td><td>落地页、表单、工具</td></tr><tr><td>SVG 图像</td><td>矢量图形</td><td>图标、流程图</td></tr><tr><td>图表/流程图</td><td>Mermaid 语法渲染</td><td>时序图、流程图、ER 图</td></tr><tr><td>React 组件</td><td>可交互的前端组件</td><td>数据可视化、计算器</td></tr></tbody></table><h3 id="如何使用-2" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用-2" aria-label="Permalink to &quot;如何使用&quot;">​</a></h3><ul><li><strong>编辑迭代</strong>：直接要求 Claude 修改，变更实时显示在 Artifact 窗口</li><li><strong>版本切换</strong>：右上角的版本选择器可以回溯历史版本</li><li><strong>导出</strong>：右下角可查看源码、复制到剪贴板、下载文件</li><li><strong>多个 Artifact</strong>：一次对话可生成多个，通过滑块图标切换</li></ul><h3 id="ai-驱动的-artifacts-高级功能" tabindex="-1">AI 驱动的 Artifacts（高级功能） <a class="header-anchor" href="#ai-驱动的-artifacts-高级功能" aria-label="Permalink to &quot;AI 驱动的 Artifacts（高级功能）&quot;">​</a></h3><p>Pro 用户可创建<strong>嵌入了 Claude 智能的应用</strong>：</p><ul><li>Artifact 内部可调用 Claude API，实现真正的交互逻辑</li><li>通过 MCP 集成连接 Asana、Google Calendar 等外部服务</li><li>支持持久化数据存储（每个 Artifact 最大 20MB）</li><li>分享给他人使用时，对方使用自己的账户，不消耗你的额度</li></ul><hr><h2 id="memory-跨对话记忆" tabindex="-1">Memory 跨对话记忆 <a class="header-anchor" href="#memory-跨对话记忆" aria-label="Permalink to &quot;Memory 跨对话记忆&quot;">​</a></h2><h3 id="是什么-6" tabindex="-1">是什么 <a class="header-anchor" href="#是什么-6" aria-label="Permalink to &quot;是什么&quot;">​</a></h3><p>Memory 让 Claude 能跨对话记住你的偏好、背景信息和工作习惯，不再每次都要重新介绍自己。</p><h3 id="两种记忆类型" tabindex="-1">两种记忆类型 <a class="header-anchor" href="#两种记忆类型" aria-label="Permalink to &quot;两种记忆类型&quot;">​</a></h3><p><strong>用户主动记忆</strong>：你明确告诉 Claude 记住某事：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>记住：我是一个前端工程师，主要用 React + TypeScript，</span></span>
<span class="line"><span>偏好函数式编程，不喜欢 class 组件。</span></span></code></pre></div><p><strong>自动记忆</strong>（Claude Code 中）：Claude 在工作时自动学习并保存，如构建命令、调试偏好、常用工具配置。</p><h3 id="如何管理记忆" tabindex="-1">如何管理记忆 <a class="header-anchor" href="#如何管理记忆" aria-label="Permalink to &quot;如何管理记忆&quot;">​</a></h3><ul><li>进入 <strong>账户设置 → 记忆</strong> 查看所有已保存的记忆</li><li>可以编辑或删除不需要的条目</li><li>支持导入/导出记忆（便于备份或在多设备同步）</li></ul><hr><h2 id="skills-技能系统" tabindex="-1">Skills 技能系统 <a class="header-anchor" href="#skills-技能系统" aria-label="Permalink to &quot;Skills 技能系统&quot;">​</a></h2><h3 id="是什么-7" tabindex="-1">是什么 <a class="header-anchor" href="#是什么-7" aria-label="Permalink to &quot;是什么&quot;">​</a></h3><p>Skills 是&quot;包含指令、脚本和资源的文件夹，Claude 动态加载来提升专项任务性能&quot;。简单说：技能让 Claude 在特定任务上更专业、更稳定。</p><h3 id="四种技能类型" tabindex="-1">四种技能类型 <a class="header-anchor" href="#四种技能类型" aria-label="Permalink to &quot;四种技能类型&quot;">​</a></h3><p><strong>Anthropic 内置技能</strong>：处理 Excel、Word、PowerPoint、PDF 等文档任务时自动调用，无需手动操作。</p><p><strong>自定义技能</strong>：你或团队创建的专属工作流，如品牌风格指南应用、标准化邮件模板、会议记录整理格式。</p><p><strong>合作伙伴技能</strong>：来自 Notion、Figma、Atlassian 等产品的预构建技能，配合对应连接器使用。</p><p><strong>组织技能（Team/Enterprise）</strong>：管理员为全团队统一部署的标准化工作流。</p><h3 id="如何使用-3" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用-3" aria-label="Permalink to &quot;如何使用&quot;">​</a></h3><p>在账户 <strong>自定义</strong> 菜单中的 <strong>技能</strong> 目录，可以查看、启用和管理所有可用技能。使用时，Claude 会自动识别当前任务是否有对应技能并加载，也可以手动用 <code>/技能名</code> 调用。</p><h3 id="如何创建自定义技能" tabindex="-1">如何创建自定义技能 <a class="header-anchor" href="#如何创建自定义技能" aria-label="Permalink to &quot;如何创建自定义技能&quot;">​</a></h3><p>详见官方文档：<a href="https://support.claude.com/zh-CN/articles/12512198" target="_blank" rel="noreferrer">如何创建自定义技能</a>。核心是：用 Markdown 写指令文件，可选配 Python 脚本，放入规定目录结构。</p><hr><h2 id="个性化设置" tabindex="-1">个性化设置 <a class="header-anchor" href="#个性化设置" aria-label="Permalink to &quot;个性化设置&quot;">​</a></h2><h3 id="自定义样式-response-style" tabindex="-1">自定义样式（Response Style） <a class="header-anchor" href="#自定义样式-response-style" aria-label="Permalink to &quot;自定义样式（Response Style）&quot;">​</a></h3><p>在 <strong>设置 → 自定义样式</strong> 中定义 Claude 的回复风格：</p><ul><li><strong>简洁模式</strong>：只给答案，不要解释</li><li><strong>教学模式</strong>：详细说明每个步骤的原因</li><li><strong>技术模式</strong>：使用专业术语，面向开发者</li><li><strong>创意模式</strong>：更有创意和个性的表达</li></ul><p>可以用自然语言描述你期望的风格，Claude 会应用到后续对话。</p><h3 id="语言设置" tabindex="-1">语言设置 <a class="header-anchor" href="#语言设置" aria-label="Permalink to &quot;语言设置&quot;">​</a></h3><p>Claude 默认用你提问的语言回答。如果你希望 Claude 始终用特定语言（如简体中文）回答，即使你用英文提问，可以在系统提示或项目指令中指定。</p><h3 id="外观设置" tabindex="-1">外观设置 <a class="header-anchor" href="#外观设置" aria-label="Permalink to &quot;外观设置&quot;">​</a></h3><p>在 <strong>设置 → 外观</strong> 中切换：</p><ul><li>亮色/暗色/跟随系统</li><li>字体大小</li></ul><h3 id="模型切换" tabindex="-1">模型切换 <a class="header-anchor" href="#模型切换" aria-label="Permalink to &quot;模型切换&quot;">​</a></h3><p>点击对话框右上角或设置中的模型选择器，可以在以下模型间切换：</p><table tabindex="0"><thead><tr><th>模型</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>Claude Opus 4.6</td><td>最强推理、最高质量，世界最强编程模型</td><td>复杂任务、深度分析、企业级代理</td></tr><tr><td>Claude Sonnet 4.6</td><td>前沿智能与速度平衡，企业工作流首选</td><td>日常开发、写作（默认）</td></tr><tr><td>Claude Haiku 4.5</td><td>最快响应，接近前沿智能</td><td>简单问答、批量处理</td></tr></tbody></table><hr><h2 id="隐私与安全" tabindex="-1">隐私与安全 <a class="header-anchor" href="#隐私与安全" aria-label="Permalink to &quot;隐私与安全&quot;">​</a></h2><h3 id="隐私聊天" tabindex="-1">隐私聊天 <a class="header-anchor" href="#隐私聊天" aria-label="Permalink to &quot;隐私聊天&quot;">​</a></h3><p><strong>隐私聊天</strong>是一种特殊对话模式，在此模式下的内容：</p><ul><li>不会被用于 Anthropic 的模型训练</li><li>不会出现在你的对话历史中（本地和云端都不保存）</li><li>会话结束后彻底清除</li></ul><p>启用方式：在新建对话时选择 <strong>隐私聊天</strong> 选项。</p><p><strong>适用场景</strong>：讨论敏感商业信息、个人隐私内容、竞争情报等不希望留存记录的对话。</p><h3 id="数据导出" tabindex="-1">数据导出 <a class="header-anchor" href="#数据导出" aria-label="Permalink to &quot;数据导出&quot;">​</a></h3><p>在 <strong>账户设置 → 数据控制</strong> 中可以导出你的所有对话历史和账户数据，格式为 JSON。</p><hr><h2 id="对话管理" tabindex="-1">对话管理 <a class="header-anchor" href="#对话管理" aria-label="Permalink to &quot;对话管理&quot;">​</a></h2><h3 id="分享对话" tabindex="-1">分享对话 <a class="header-anchor" href="#分享对话" aria-label="Permalink to &quot;分享对话&quot;">​</a></h3><p>已完成的对话可以生成分享链接，发给他人查看（只读，对方无法继续对话）。在对话右上角点击 <strong>分享</strong> 图标，可以设置是否公开。</p><h3 id="搜索历史对话" tabindex="-1">搜索历史对话 <a class="header-anchor" href="#搜索历史对话" aria-label="Permalink to &quot;搜索历史对话&quot;">​</a></h3><p>左侧边栏顶部有搜索框，可以全文搜索历史对话内容，快速找到之前讨论过的话题。</p><h3 id="上传文件" tabindex="-1">上传文件 <a class="header-anchor" href="#上传文件" aria-label="Permalink to &quot;上传文件&quot;">​</a></h3><p>在对话框中可以直接拖拽或点击附件图标上传文件。支持文档、代码、图片、PDF 等格式，Claude 会分析文件内容并基于其回答问题。</p><hr><h2 id="使用量管理" tabindex="-1">使用量管理 <a class="header-anchor" href="#使用量管理" aria-label="Permalink to &quot;使用量管理&quot;">​</a></h2><h3 id="理解使用限制" tabindex="-1">理解使用限制 <a class="header-anchor" href="#理解使用限制" aria-label="Permalink to &quot;理解使用限制&quot;">​</a></h3><p>Pro 用户享有 <strong>Standard</strong> 级使用量（远高于 Free 的 Limited），但仍有上限（Max 5x 计划是 Pro 的 5 倍）。使用量按以下顺序消耗更快：</p><ol><li>普通对话（最省）</li><li>开启网络搜索的对话</li><li>Extended Thinking 对话</li><li>Research 对话（最耗）</li></ol><h3 id="如何查看使用情况" tabindex="-1">如何查看使用情况 <a class="header-anchor" href="#如何查看使用情况" aria-label="Permalink to &quot;如何查看使用情况&quot;">​</a></h3><p>在 <strong>设置 → 使用情况</strong> 中可以查看当前周期的额度消耗情况。</p><h3 id="使用量套餐" tabindex="-1">使用量套餐 <a class="header-anchor" href="#使用量套餐" aria-label="Permalink to &quot;使用量套餐&quot;">​</a></h3><p>如果你的 Pro 额度不够用，可以购买额外的使用量套餐（按量付费），无需升级到 Max 计划。进入账户设置查看套餐选项。</p><h3 id="最佳实践-省额度的用法" tabindex="-1">最佳实践：省额度的用法 <a class="header-anchor" href="#最佳实践-省额度的用法" aria-label="Permalink to &quot;最佳实践：省额度的用法&quot;">​</a></h3><ul><li>只在必要时启用 Extended Thinking 和 Research</li><li>将重复性问题做成项目知识库，避免每次粘贴相同背景</li><li>简单问题直接问，不要加过多上下文</li><li>用 Claude Haiku 处理简单批量任务</li></ul><hr><h2 id="实用场景示例" tabindex="-1">实用场景示例 <a class="header-anchor" href="#实用场景示例" aria-label="Permalink to &quot;实用场景示例&quot;">​</a></h2><h3 id="场景-1-技术调研-research-projects" tabindex="-1">场景 1：技术调研（Research + Projects） <a class="header-anchor" href="#场景-1-技术调研-research-projects" aria-label="Permalink to &quot;场景 1：技术调研（Research + Projects）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 创建 Project：&quot;技术选型调研&quot;</span></span>
<span class="line"><span>2. 上传现有系统架构文档</span></span>
<span class="line"><span>3. 启用 Research 功能</span></span>
<span class="line"><span>4. 问：请调研 React Server Components vs 传统 CSR 在我们这类电商场景下的适用性，</span></span>
<span class="line"><span>   结合我上传的架构文档给出建议。</span></span></code></pre></div><h3 id="场景-2-复杂问题规划-extended-thinking" tabindex="-1">场景 2：复杂问题规划（Extended Thinking） <a class="header-anchor" href="#场景-2-复杂问题规划-extended-thinking" aria-label="Permalink to &quot;场景 2：复杂问题规划（Extended Thinking）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 选择 Claude 4，启用 Extended Thinking</span></span>
<span class="line"><span>2. 问：我需要将一个 jQuery 项目迁移到 React，</span></span>
<span class="line"><span>   项目有 200 个页面，团队 5 人，需要 3 个月完成。</span></span>
<span class="line"><span>   请帮我制定详细的迁移策略和风险控制方案。</span></span></code></pre></div><h3 id="场景-3-生成可交互原型-artifacts" tabindex="-1">场景 3：生成可交互原型（Artifacts） <a class="header-anchor" href="#场景-3-生成可交互原型-artifacts" aria-label="Permalink to &quot;场景 3：生成可交互原型（Artifacts）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>问：用 React 帮我做一个数据表格组件，支持排序、筛选、分页，</span></span>
<span class="line"><span>使用 Tailwind CSS 样式，数据从 props 传入。</span></span></code></pre></div><p>→ Claude 生成 Artifact，右侧直接预览效果，不满意可继续迭代。</p><h3 id="场景-4-个性化写作助手-projects-自定义指令" tabindex="-1">场景 4：个性化写作助手（Projects + 自定义指令） <a class="header-anchor" href="#场景-4-个性化写作助手-projects-自定义指令" aria-label="Permalink to &quot;场景 4：个性化写作助手（Projects + 自定义指令）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>项目指令：</span></span>
<span class="line"><span>你是一位技术写作专家，帮我写面向前端开发者的技术博客。</span></span>
<span class="line"><span>文章风格：直接、有深度、带实际代码示例。</span></span>
<span class="line"><span>避免：过多废话、过于学术化的表达。</span></span>
<span class="line"><span>读者假设：有 2 年以上 React 经验的开发者。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>知识库：上传你过去的文章作为风格参考</span></span></code></pre></div><hr><h2 id="资源链接" tabindex="-1">资源链接 <a class="header-anchor" href="#资源链接" aria-label="Permalink to &quot;资源链接&quot;">​</a></h2><ul><li><a href="https://support.claude.com/zh-CN/articles/9517075" target="_blank" rel="noreferrer">什么是 Projects</a></li><li><a href="https://support.claude.com/zh-CN/articles/10574485" target="_blank" rel="noreferrer">使用扩展思考</a></li><li><a href="https://support.claude.com/zh-CN/articles/11088861" target="_blank" rel="noreferrer">使用 Claude 进行研究</a></li><li><a href="https://support.claude.com/zh-CN/articles/9487310" target="_blank" rel="noreferrer">什么是 Artifacts</a></li><li><a href="https://support.claude.com/zh-CN/articles/12512176" target="_blank" rel="noreferrer">什么是技能</a></li><li><a href="https://support.claude.com/zh-CN/articles/11049762" target="_blank" rel="noreferrer">选择 Claude 计划</a></li><li><a href="https://support.claude.com/zh-CN/articles/11647753" target="_blank" rel="noreferrer">理解使用情况和长度限制</a></li></ul>`,159)])])}const k=t(i,[["render",n]]);export{q as __pageData,k as default};
